rt:" };\n            NumericUpDown numPort = new NumericUpDown();\n            Button btnTestPython = new Button() { Text = "Test" };\n            tabPythonServices.Controls.Add(lblPythonPath);\n            tabPythonServices.Controls.Add(txtPythonPath);\n            tabPythonServices.Controls.Add(lblPort);\n            tabPythonServices.Controls.Add(numPort);\n            tabPythonServices.Controls.Add(btnTestPython);\n\n            // Logging Tab\n            Label lblLogLevel = new Label() { Text = "Log Level:" };\n            ComboBox cmbLogLevel = new ComboBox(); // Populate log levels\n            Button btnOpenFolder = new Button() { Text = "Open Folder" };\n            tabLogging.Controls.Add(lblLogLevel);\n            tabLogging.Controls.Add(cmbLogLevel);\n            tabLogging.Controls.Add(btnOpenFolder);\n            \n            this.Controls.Add(tabControl);\n        }\n    }\n}